const data = $getWorkflowStaticData('global');

if (!data.lastRun) {
  const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
  data.lastRun = yesterday.toISOString();
}

return [{
  json: {
    lastRun: data.lastRun,
    filter: `lastmodifieddate:[${data.lastRun}..]`,
  }
}];

const data = $getWorkflowStaticData('global');
const processedIds = data.processedIds || [];

const orders = $input.first().json.orders;

const newOrders = orders.filter(order => 
  !processedIds.some(entry => entry.id === order.orderId) &&
  order.orderFulfillmentStatus === 'NOT_STARTED'
);

if (newOrders.length === 0) {
  return [];
}

return newOrders.map(order => ({ json: order }));

const ebayOrders = $('If1').all().map(i => i.json);
const unprocessedSheetRows = $('If2').all().map(i => i.json);

// Build set of unprocessed sale_refs from sheet
const unprocessedRefs = new Set(unprocessedSheetRows.map(r => String(r.sale_ref)));

// Only transform eBay orders that are unprocessed in sheet
const newOrders = ebayOrders.filter(order =>
  unprocessedRefs.has(String(order.salesRecordReference))
);

if (newOrders.length === 0) return [];

return newOrders.map(order => {
  const shipTo = order.fulfillmentStartInstructions[0].shippingStep.shipTo;
  const address = shipTo.contactAddress;
  const streetAddress = address.addressLine2 || address.addressLine1;

  const orderDate = new Date(order.creationDate).toLocaleDateString('en-AU', {
    day: '2-digit',
    month: 'long',
    year: 'numeric',
  });

  const toNumber = (v) => {
    if (v === null || v === undefined) return 0;
    if (typeof v === 'number') return v;
    const n = Number(String(v).replace(/[^0-9.-]/g, ''));
    return Number.isFinite(n) ? n : 0;
  };

  const payment_gateway_names = order.paymentSummary.payments.map(p => p.paymentMethod);
  const payment_gateways = payment_gateway_names.join(', ');

  const shipping_address = [
    streetAddress,
    [address.city, address.stateOrProvince, address.postalCode].filter(Boolean).join(' '),
    address.countryCode,
  ].filter(Boolean).join('\n');

  const line_items_structured = order.lineItems.map(item => ({
    title: item.title,
    sku: 'n/a',
    quantity: item.quantity,
    price_each: toNumber(item.lineItemCost.value),
    product_url: `https://www.ebay.com.au/itm/${item.legacyItemId}`,
    product_id: item.legacyItemId,
    variant_id: null,
    variant_gid: null,
    image_url: null,
    legacyItemId: item.legacyItemId,
  }));

  return {
    json: {
      order_id: order.orderId,
      order_number: order.salesRecordReference,
      order_date: orderDate,
      shipping_name: shipTo.fullName,
      shipping_address,
      billing_name: shipTo.fullName,
      billing_address: shipping_address,
      shipping_title: order.fulfillmentStartInstructions[0].shippingStep.shippingCarrierCode,
      shipping_price: toNumber(order.pricingSummary.deliveryCost.value),
      payment_gateway_names,
      payment_gateways,
      subtotal: toNumber(order.pricingSummary.priceSubtotal.value),
      total_paid: toNumber(order.pricingSummary.total.value),
      line_items_structured,
      salesRecord: order.salesRecordReference,
      deliveryMin: order.fulfillmentStartInstructions[0].minEstimatedDeliveryDate,
      deliveryMax: order.fulfillmentStartInstructions[0].maxEstimatedDeliveryDate,
    }
  };
});

const orders = $('Code in JavaScript5').all().map(i => i.json);
const sheetRows = $input.all().map(i => i.json);

const skuMap = {};
for (const row of sheetRows) {
  skuMap[String(row.item_id)] = row.sku;
}

return orders.map(order => ({
  json: {
    ...order,
    line_items_structured: order.line_items_structured.map(item => ({
      ...item,
      sku: skuMap[String(item.product_id)] || 'n/a',
    })),
  }
}));

const orders = $input.all().map(i => i.json);

const items = [];
for (const order of orders) {
  for (const lineItem of order.line_items_structured) {
    items.push({
      json: {
        ...lineItem,
        _orderId: order.order_id,
        _orderData: order,
      }
    });
  }
}

return items;

const browseItems = $('HTTP Request2').all().map(i => i.json);
const originalItems = $('Code in JavaScript7').all().map(i => i.json);

const orderMap = {};

for (let idx = 0; idx < originalItems.length; idx++) {
  const original = originalItems[idx];
  const browse = browseItems[idx];
  const orderId = original._orderId;

  if (!orderMap[orderId]) {
    orderMap[orderId] = {
      ...original._orderData,
      line_items_structured: [],
    };
  }

  orderMap[orderId].line_items_structured.push({
    title: original.title,
    sku: original.sku,
    quantity: original.quantity,
    price_each: original.price_each,
    product_url: original.product_url,
    product_id: original.product_id,
    variant_id: original.variant_id,
    variant_gid: original.variant_gid,
    legacyItemId: original.legacyItemId,
    image_url: browse.image?.imageUrl || null,
  });
}

return Object.values(orderMap).map(order => ({ json: order }));

const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const docItem = $input.all()[i];
  const orderItem = $('Code in JavaScript8').all()[i];

  const documentId = $('Update a document2').all()[i].json.documentId;
  const anchorStartIndex = docItem.json.body.content[8].paragraph.elements[0].startIndex;
  const anchorEndIndex = docItem.json.body.content[8].paragraph.elements[0].endIndex;
  const items = orderItem.json.line_items_structured || [];

  if (!documentId) throw new Error("Missing documentId for item " + i);
  if (!anchorStartIndex || !anchorEndIndex) throw new Error("Missing anchor indices for item " + i);

  const requests = [];
  const reversed = [...items].reverse();

  function hasRealSku(rawSku) {
    if (rawSku === null || rawSku === undefined) return false;
    const s = String(rawSku).trim();
    if (!s) return false;
    const lowered = s.toLowerCase();
    if (lowered === "n/a" || lowered === "na" || lowered === "none" || lowered === "null" || lowered === "-") return false;
    // Split on spaces and validate each part
    const parts = s.split(' ').filter(Boolean);
    return parts.every(part => /^[A-Za-z]{2,3}-\d{3}$/.test(part));
  }

  for (const item of reversed) {
    const qty = (item.quantity ?? "").toString().trim() || "0";
    const title = (item.title ?? "").toString().trim() || "";
    const imageUrl = (item.image_url ?? "").toString().trim();

    const skuLine = hasRealSku(item.sku)
      ? `SKU: ${String(item.sku).trim()}     QTY: ${qty}\n`
      : `QTY: ${qty}\n`;

    requests.push({ insertText: { location: { index: anchorStartIndex }, text: "\n" } });

    if (imageUrl) {
      requests.push({ insertText: { location: { index: anchorStartIndex }, text: "\n" } });
      requests.push({
        insertInlineImage: {
          location: { index: anchorStartIndex },
          uri: imageUrl,
          objectSize: {
            height: { magnitude: 100, unit: "PT" },
            width: { magnitude: 100, unit: "PT" },
          },
        },
      });
    }

    requests.push({ insertText: { location: { index: anchorStartIndex }, text: `${title}\n` } });
    requests.push({ insertText: { location: { index: anchorStartIndex }, text: skuLine } });
  }

  results.push({ json: { documentId, requests } });
}

return results;

